import{_ as t,o as a,c as o,a2 as n}from"./chunks/framework.ufzXw1qY.js";const g=JSON.parse('{"title":"🏷️ Naming Conventions & SSOT","description":"","frontmatter":{},"headers":[],"relativePath":"guide/naming-conventions.md","filePath":"guide/naming-conventions.md"}'),r={name:"guide/naming-conventions.md"};function i(s,e,d,c,l,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="🏷️-naming-conventions-ssot" tabindex="-1">🏷️ Naming Conventions &amp; SSOT <a class="header-anchor" href="#🏷️-naming-conventions-ssot" aria-label="Permalink to &quot;🏷️ Naming Conventions &amp; SSOT&quot;">​</a></h1><h2 id="the-ultimate-ssot" tabindex="-1">The Ultimate SSOT <a class="header-anchor" href="#the-ultimate-ssot" aria-label="Permalink to &quot;The Ultimate SSOT&quot;">​</a></h2><p>Before modifying any code or reading further, you must be aware of the <strong><a href="https://github.com/OpenSIN-AI/OpenSIN-overview" target="_blank" rel="noreferrer">OpenSIN-overview</a></strong> repository. It is the Single Source of Truth for the entire organization.</p><h2 id="strict-naming-schema" tabindex="-1">Strict Naming Schema <a class="header-anchor" href="#strict-naming-schema" aria-label="Permalink to &quot;Strict Naming Schema&quot;">​</a></h2><p>To prevent architectural chaos, every repository in the OpenSIN-AI organization <strong>MUST</strong> follow this strict naming schema:</p><p><code>[Type]-SIN-[Name]</code></p><h3 id="valid-types" tabindex="-1">Valid Types: <a class="header-anchor" href="#valid-types" aria-label="Permalink to &quot;Valid Types:&quot;">​</a></h3><ul><li><code>Team-SIN-*</code> (Orchestrators, Hubs, Managers. E.g., <code>Team-SIN-Legal</code>)</li><li><code>A2A-SIN-*</code> (Worker Agents that execute tasks. E.g., <code>A2A-SIN-ClaimWriter</code>)</li><li><code>MCP-SIN-*</code> (Model Context Protocol Servers / Tools. E.g., <code>MCP-SIN-Browser</code>)</li><li><code>CLI-SIN-*</code> (Command Line Interfaces / Terminals. E.g., <code>CLI-SIN-Code</code>)</li><li><code>Template-SIN-*</code> (Blueprints for the forge scripts)</li></ul><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Doku</th></tr></thead><tbody><tr><td><strong>Bun-Only</strong></td><td>-1.5</td><td><code>bun install</code> / <code>bun run</code> statt npm</td></tr><tr><td><strong>Annahmen-Verbot</strong></td><td>-5.0</td><td>KEINE Diagnose ohne Beweis</td></tr><tr><td><strong>Test-Beweis-Pflicht</strong></td><td>0.0</td><td>KEIN &quot;Done&quot; ohne echten Test-Lauf</td></tr></tbody></table><p>→ <a href="/best-practices/code-quality.html">Alle Mandate</a></p>',12)])])}const u=t(r,[["render",i]]);export{g as __pageData,u as default};
